      { name: "Swift Project 5", code:`import Foundation\nstruct Product{var id:Int;var name:String;var price:Int;var stock:Int}\nstruct User{var id:Int;var name:String;var email:String;var active:Bool}\nstruct Order{var id:Int;var userId:Int;var productId:Int;var qty:Int;var total:Int}\nvar products:[Product]=[]\nvar users:[User]=[]\nvar orders:[Order]=[]\nfunc addProduct(_ n:String,_ p:Int,_ s:Int){products.append(Product(id:products.count+1,name:n,price:p,stock:s))}\nfunc addUser(_ n:String,_ e:String,_ a:Bool=true){users.append(User(id:users.count+1,name:n,email:e,active:a))}\nfunc placeOrder(_ uid:Int,_ pid:Int,_ q:Int){guard let p=products.first(where:{$0.id==pid}),let u=users.first(where:{$0.id==uid}),p.stock>=q else{print(\"Failed\");return};let total=p.price*q;products[p.id-1].stock-=q;orders.append(Order(id:orders.count+1,userId:uid,productId:pid,qty:q,total:total));print(\"ORDER SUCCESS \\(total)\")}\nfunc analytics(){let revenue=orders.reduce(0){$0+$1.total};let stock=products.reduce(0){$0+$1.stock};let activeUsers=users.filter{$0.active}.count;let top=users.max(by:{$0.id<$1.id});print(\"=== ANALYTICS ===\");print(\"Users:\\(users.count) Active:\\(activeUsers)\");print(\"Products:\\(products.count) Stock:\\(stock)\");print(\"Revenue:\\(revenue)\");print(\"Top User:\\(top?.name ?? \"\")\")}\naddProduct(\"Laptop\",70000,10)\naddProduct(\"Mouse\",1500,50)\naddProduct(\"Keyboard\",3000,30)\naddUser(\"Aman\",\"a@mail.com\",true)\naddUser(\"Neha\",\"n@mail.com\",true)\naddUser(\"Ravi\",\"r@mail.com\",false)\nplaceOrder(1,1,1)\nplaceOrder(2,2,2)\nplaceOrder(3,3,1)\nanalytics()\n`  },
      { name: "Swift Project 6", code:`import Foundation\nstruct Employee{let id:Int;let name:String;let department:String;let salary:Int;let experience:Int;let active:Bool}\nstruct Project{let id:Int;let title:String;let progress:Int;let budget:Int;let status:String}\nlet employees=[\nEmployee(id:101,name:"Aman",department:"iOS",salary:78000,experience:5,active:true),\nEmployee(id:102,name:"Neha",department:"Backend",salary:86000,experience:7,active:true),\nEmployee(id:103,name:"Ravi",department:"UI",salary:64000,experience:3,active:false),\nEmployee(id:104,name:"Priya",department:"Testing",salary:59000,experience:4,active:true),\nEmployee(id:105,name:"Arjun",department:"DevOps",salary:91000,experience:8,active:true),\nEmployee(id:106,name:"Sneha",department:"Security",salary:98000,experience:9,active:true)\n]\nlet projects=[\nProject(id:1,title:"Finance App",progress:82,budget:2400000,status:"Running"),\nProject(id:2,title:"Travel App",progress:67,budget:1800000,status:"Running"),\nProject(id:3,title:"CRM Dashboard",progress:100,budget:1500000,status:"Completed"),\nProject(id:4,title:"Food Delivery",progress:58,budget:2100000,status:"Testing"),\nProject(id:5,title:"Healthcare",progress:91,budget:2700000,status:"Review")\n]\nlet activeEmployees=employees.filter{$0.active}\nlet totalSalary=employees.reduce(0){$0+$1.salary}\nlet averageSalary=totalSalary/employees.count\nlet totalBudget=projects.reduce(0){$0+$1.budget}\nlet runningProjects=projects.filter{$0.status=="Running"}\nlet highestSalary=employees.max{$0.salary<$1.salary}\nprint("=========== COMPANY MANAGEMENT ===========")\nprint("Employees:",employees.count)\nprint("Projects:",projects.count)\nprint("Active Employees:",activeEmployees.count)\nprint("Total Salary:",totalSalary)\nprint("Average Salary:",averageSalary)\nprint("Project Budget:",totalBudget)\nif let emp=highestSalary{print("Highest Salary:",emp.name,emp.salary)}\nprint("===== EMPLOYEE LIST =====")\nemployees.forEach{print($0.id,$0.name,$0.department,$0.salary,$0.experience)}\nprint("===== PROJECTS =====")\nprojects.forEach{print($0.id,$0.title,$0.progress,$0.status)}\nprint("===== RUNNING PROJECTS =====")\nrunningProjects.forEach{print($0.title,$0.progress)}\nlet dashboard=[\"Server\":\"Online\",\"Database\":\"Connected\",\"Security\":\"Enabled\",\"Backup\":\"Completed\",\"Version\":\"2.4.1\",\"Analytics\":\"Ready\"]\nprint(\"===== DASHBOARD =====\")\ndashboard.forEach{print($0.key,$0.value)}\nlet modules=[\"Dashboard\",\"Employees\",\"Projects\",\"Reports\",\"Analytics\",\"Settings\",\"Support\"]\nmodules.forEach{print($0)}\nprint(\"Company Dashboard Loaded Successfully\")` },
      { name: "Swift Project 7", code:`import Foundation\nstruct Product{let id:Int;let name:String;let category:String;let price:Int;let stock:Int;let sold:Int;let rating:Double;let available:Bool}\nstruct Customer{let id:Int;let name:String;let orders:Int;let spent:Int;let premium:Bool}\nstruct Order{let id:Int;let customer:String;let product:String;let quantity:Int;let amount:Int;let status:String}\nlet products=[\nProduct(id:101,name:"Laptop Pro",category:"Laptop",price:72000,stock:28,sold:165,rating:4.9,available:true),\nProduct(id:102,name:"Gaming Mouse",category:"Accessories",price:2400,stock:90,sold:420,rating:4.8,available:true),\nProduct(id:103,name:"Mechanical Keyboard",category:"Accessories",price:5200,stock:48,sold:310,rating:4.7,available:true),\nProduct(id:104,name:"Monitor HD",category:"Monitor",price:16800,stock:22,sold:148,rating:4.8,available:true),\nProduct(id:105,name:"Smart Watch",category:"Wearable",price:9800,stock:35,sold:265,rating:4.6,available:true),\nProduct(id:106,name:"Bluetooth Speaker",category:"Audio",price:4300,stock:76,sold:352,rating:4.7,available:true),\nProduct(id:107,name:"Power Bank",category:"Accessories",price:2100,stock:110,sold:488,rating:4.5,available:true)\n]\nlet customers=[\nCustomer(id:1,name:"Aman",orders:15,spent:98000,premium:true),\nCustomer(id:2,name:"Neha",orders:11,spent:64000,premium:true),\nCustomer(id:3,name:"Ravi",orders:7,spent:28500,premium:false),\nCustomer(id:4,name:"Priya",orders:13,spent:81200,premium:true),\nCustomer(id:5,name:"Arjun",orders:6,spent:24300,premium:false)\n]\nlet orders=[\nOrder(id:1001,customer:"Aman",product:"Laptop Pro",quantity:1,amount:72000,status:"Delivered"),\nOrder(id:1002,customer:"Neha",product:"Monitor HD",quantity:1,amount:16800,status:"Delivered"),\nOrder(id:1003,customer:"Priya",product:"Smart Watch",quantity:2,amount:19600,status:"Shipped"),\nOrder(id:1004,customer:"Ravi",product:"Gaming Mouse",quantity:1,amount:2400,status:"Processing"),\nOrder(id:1005,customer:"Arjun",product:"Bluetooth Speaker",quantity:2,amount:8600,status:"Delivered")\n]\nlet availableProducts=products.filter{$0.available}\nlet premiumCustomers=customers.filter{$0.premium}\nlet deliveredOrders=orders.filter{$0.status=="Delivered"}\nlet totalRevenue=orders.reduce(0){$0+$1.amount}\nlet totalStock=products.reduce(0){$0+$1.stock}\nlet totalSold=products.reduce(0){$0+$1.sold}\nlet averagePrice=products.reduce(0){$0+$1.price}/products.count\nlet bestProduct=products.max{$0.sold<$1.sold}\nprint("=========== E-COMMERCE MANAGEMENT ===========")\nprint("Products:",products.count)\nprint("Customers:",customers.count)\nprint("Orders:",orders.count)\nprint("Available Products:",availableProducts.count)\nprint("Premium Customers:",premiumCustomers.count)\nprint("Delivered Orders:",deliveredOrders.count)\nprint("Revenue:",totalRevenue)\nprint("Stock:",totalStock)\nprint("Items Sold:",totalSold)\nprint("Average Price:",averagePrice)\nif let product=bestProduct{print("Best Seller:",product.name,product.sold)}\nprint("===== PRODUCT LIST =====")\nproducts.forEach{print($0.id,$0.name,$0.category,$0.price,$0.stock,$0.sold)}\nprint("===== CUSTOMER LIST =====")\ncustomers.forEach{print($0.name,$0.orders,$0.spent,$0.premium)}\nprint("===== ORDER HISTORY =====")\norders.forEach{print($0.id,$0.customer,$0.product,$0.status,$0.amount)}\nlet analytics=[\"Visitors\":\"25480\",\"Conversion\":\"5.8%\",\"Payments\":\"Success\",\"Returns\":\"18\",\"Warehouse\":\"Updated\",\"Server\":\"Online\",\"Database\":\"Connected\",\"Security\":\"Protected\",\"Backup\":\"Completed\",\"Version\":\"3.2.0\"]\nprint(\"===== ANALYTICS =====\")\nanalytics.forEach{print($0.key,$0.value)}\nlet modules=[\"Dashboard\",\"Products\",\"Orders\",\"Customers\",\"Inventory\",\"Payments\",\"Reports\",\"Analytics\",\"Support\",\"Settings\"]\nmodules.forEach{print($0)}\nprint(\"Store Management System Started Successfully\")`  },
      { name: "Swift Project 8", code:`import Foundation\nstruct Student{let id:Int;let name:String;let course:String;let marks:[Int];let attendance:Int}\nstruct Teacher{let id:Int;let name:String;let subject:String;let experience:Int}\nstruct Subject{let code:String;let title:String;let credits:Int}\nlet students=[\nStudent(id:101,name:"Aman",course:"Computer Science",marks:[82,91,88,79],attendance:94),\nStudent(id:102,name:"Neha",course:"Information Tech",marks:[95,90,93,97],attendance:98),\nStudent(id:103,name:"Ravi",course:"Computer Science",marks:[74,81,77,80],attendance:89),\nStudent(id:104,name:"Priya",course:"Electronics",marks:[86,84,91,88],attendance:96),\nStudent(id:105,name:"Arjun",course:"Information Tech",marks:[92,89,94,90],attendance:97)\n]\nlet teachers=[\nTeacher(id:1,name:"Sharma",subject:"Programming",experience:10),\nTeacher(id:2,name:"Patil",subject:"Database",experience:8),\nTeacher(id:3,name:"Joshi",subject:"Networking",experience:12),\nTeacher(id:4,name:"Kulkarni",subject:"AI",experience:9)\n]\nlet subjects=[\nSubject(code:"CS101",title:"Programming",credits:4),\nSubject(code:"CS102",title:"Database",credits:3),\nSubject(code:"CS103",title:"Networking",credits:3),\nSubject(code:"CS104",title:"Artificial Intelligence",credits:5),\nSubject(code:"CS105",title:"Cloud Computing",credits:4)\n]\nlet totalStudents=students.count\nlet totalTeachers=teachers.count\nlet totalCredits=subjects.reduce(0){$0+$1.credits}\nlet averages=students.map{($0.name,$0.marks.reduce(0,+)/$0.marks.count)}\nlet topper=averages.max{$0.1<$1.1}\nlet excellentAttendance=students.filter{$0.attendance>=95}\nprint("=========== COLLEGE MANAGEMENT SYSTEM ===========")\nprint("Students:",totalStudents)\nprint("Teachers:",totalTeachers)\nprint("Subjects:",subjects.count)\nprint("Credits:",totalCredits)\nif let top=topper{print("Topper:",top.0,top.1)}\nprint("===== STUDENTS =====")\nstudents.forEach{print($0.id,$0.name,$0.course,$0.attendance)}\nprint("===== TEACHERS =====")\nteachers.forEach{print($0.id,$0.name,$0.subject,$0.experience)}\nprint("===== SUBJECTS =====")\nsubjects.forEach{print($0.code,$0.title,$0.credits)}\nprint("===== AVERAGE MARKS =====")\naverages.forEach{print($0.0,$0.1)}\nprint("===== EXCELLENT ATTENDANCE =====")\nexcellentAttendance.forEach{print($0.name,$0.attendance)}\nlet notices=[\"Semester Exam\":\"15 July\",\"Project Submission\":\"28 June\",\"Hackathon\":\"10 August\",\"Sports Day\":\"22 September\",\"Placement Drive\":\"October\"]\nprint(\"===== NOTICE BOARD =====\")\nnotices.forEach{print($0.key,$0.value)}\nlet departments=[\"Computer Science\",\"Information Technology\",\"Electronics\",\"Mechanical\",\"Civil\",\"AI & ML\",\"Data Science\"]\nprint(\"===== DEPARTMENTS =====\")\ndepartments.forEach{print($0)}\nlet dashboard=[\"Server\":\"Running\",\"Library\":\"Open\",\"Labs\":\"Available\",\"Hostel\":\"Active\",\"Transport\":\"Ready\",\"Portal\":\"Online\",\"Backup\":\"Completed\",\"Version\":\"5.1.2\"]\nprint(\"===== DASHBOARD =====\")\ndashboard.forEach{print($0.key,$0.value)}\nprint(\"College Management Portal Loaded Successfully\")`  },
      { name: "Swift Project 9", code:`import Foundation\nstruct Account{let number:Int;let holder:String;var balance:Double;let type:String}\nstruct Transaction{let id:Int;let account:Int;let mode:String;let amount:Double;let status:String}\nlet accounts=[\nAccount(number:1001,holder:"Aman",balance:82500.50,type:"Savings"),\nAccount(number:1002,holder:"Neha",balance:154300.00,type:"Current"),\nAccount(number:1003,holder:"Ravi",balance:45620.75,type:"Savings"),\nAccount(number:1004,holder:"Priya",balance:219800.20,type:"Business"),\nAccount(number:1005,holder:"Arjun",balance:67890.10,type:"Savings")\n]\nlet transactions=[\nTransaction(id:1,account:1001,mode:"Deposit",amount:12000,status:"Success"),\nTransaction(id:2,account:1002,mode:"Transfer",amount:35000,status:"Success"),\nTransaction(id:3,account:1003,mode:"Withdraw",amount:5000,status:"Success"),\nTransaction(id:4,account:1004,mode:"Deposit",amount:80000,status:"Pending"),\nTransaction(id:5,account:1005,mode:"Transfer",amount:9200,status:"Success"),\nTransaction(id:6,account:1002,mode:"Withdraw",amount:15000,status:"Success"),\nTransaction(id:7,account:1001,mode:"Deposit",amount:4200,status:"Success")\n]\nlet totalBalance=accounts.reduce(0.0){$0+$1.balance}\nlet totalTransactions=transactions.reduce(0.0){$0+$1.amount}\nlet successful=transactions.filter{$0.status=="Success"}\nlet deposits=transactions.filter{$0.mode=="Deposit"}\nlet transfers=transactions.filter{$0.mode=="Transfer"}\nlet richest=accounts.max{$0.balance<$1.balance}\nprint("=========== DIGITAL BANKING SYSTEM ===========")\nprint("Accounts:",accounts.count)\nprint("Transactions:",transactions.count)\nprint("Successful:",successful.count)\nprint("Deposits:",deposits.count)\nprint("Transfers:",transfers.count)\nprint("Bank Balance:",totalBalance)\nprint("Transaction Value:",totalTransactions)\nif let user=richest{print("Highest Balance:",user.holder,user.balance)}\nprint("===== ACCOUNT DETAILS =====")\naccounts.forEach{print($0.number,$0.holder,$0.type,$0.balance)}\nprint("===== TRANSACTION LOG =====")\ntransactions.forEach{print($0.id,$0.account,$0.mode,$0.amount,$0.status)}\nlet services=[\"UPI\",\"NEFT\",\"RTGS\",\"IMPS\",\"Card Control\",\"Loan\",\"Insurance\",\"Fixed Deposit\",\"Credit Card\",\"Net Banking\"]\nprint(\"===== SERVICES =====\")\nservices.forEach{print($0)}\nlet dashboard=[\"Server\":\"Online\",\"ATM\":\"Connected\",\"UPI\":\"Available\",\"Cards\":\"Active\",\"Security\":\"Protected\",\"Backup\":\"Completed\",\"Fraud Check\":\"Enabled\",\"Version\":\"8.0.4\"]\nprint(\"===== SYSTEM STATUS =====\")\ndashboard.forEach{print($0.key,$0.value)}\nlet rates=[\"Savings\":\"3.5%\",\"FD\":\"7.2%\",\"Home Loan\":\"8.4%\",\"Car Loan\":\"9.1%\",\"Gold Loan\":\"8.8%\"]\nprint(\"===== INTEREST RATES =====\")\nrates.forEach{print($0.key,$0.value)}\nprint(\"Digital Banking Platform Ready\")`  },
      { name: "Swift Project 10", code:`import Foundation\nstruct Flight{let id:String;let from:String;let to:String;let seats:Int;let booked:Int;let price:Double;let status:String}\nstruct Passenger{let id:Int;let name:String;let flight:String;let seat:String;let checkedIn:Bool}\nstruct Booking{let id:Int;let passenger:String;let flight:String;let payment:Double;let method:String;let confirmed:Bool}\nlet flights=[\nFlight(id:"AI101",from:"Mumbai",to:"Delhi",seats:180,booked:162,price:6450,status:"On Time"),\nFlight(id:"AI202",from:"Delhi",to:"Bengaluru",seats:220,booked:201,price:7920,status:"Boarding"),\nFlight(id:"AI303",from:"Pune",to:"Hyderabad",seats:150,booked:118,price:5240,status:"On Time"),\nFlight(id:"AI404",from:"Chennai",to:"Goa",seats:170,booked:149,price:5830,status:"Delayed"),\nFlight(id:"AI505",from:"Kolkata",to:"Mumbai",seats:210,booked:206,price:8640,status:"Boarding"),\nFlight(id:"AI606",from:"Ahmedabad",to:"Jaipur",seats:160,booked:132,price:4710,status:"On Time")\n]\nlet passengers=[\nPassenger(id:1,name:"Aman",flight:"AI101",seat:"12A",checkedIn:true),\nPassenger(id:2,name:"Neha",flight:"AI202",seat:"04C",checkedIn:true),\nPassenger(id:3,name:"Ravi",flight:"AI303",seat:"18F",checkedIn:false),\nPassenger(id:4,name:"Priya",flight:"AI404",seat:"09B",checkedIn:true),\nPassenger(id:5,name:"Arjun",flight:"AI505",seat:"21D",checkedIn:true),\nPassenger(id:6,name:"Sneha",flight:"AI606",seat:"03A",checkedIn:false),\nPassenger(id:7,name:"Karan",flight:"AI202",seat:"15E",checkedIn:true)\n]\nlet bookings=[\nBooking(id:1001,passenger:"Aman",flight:"AI101",payment:6450,method:"UPI",confirmed:true),\nBooking(id:1002,passenger:"Neha",flight:"AI202",payment:7920,method:"Card",confirmed:true),\nBooking(id:1003,passenger:"Ravi",flight:"AI303",payment:5240,method:"NetBanking",confirmed:true),\nBooking(id:1004,passenger:"Priya",flight:"AI404",payment:5830,method:"UPI",confirmed:true),\nBooking(id:1005,passenger:"Arjun",flight:"AI505",payment:8640,method:"Card",confirmed:true),\nBooking(id:1006,passenger:"Sneha",flight:"AI606",payment:4710,method:"Wallet",confirmed:false)\n]\nlet totalRevenue=bookings.reduce(0.0){$0+$1.payment}\nlet checkedPassengers=passengers.filter{$0.checkedIn}\nlet confirmedBookings=bookings.filter{$0.confirmed}\nlet availableSeats=flights.reduce(0){$0+($1.seats-$1.booked)}\nlet totalSeats=flights.reduce(0){$0+$1.seats}\nlet bookedSeats=flights.reduce(0){$0+$1.booked}\nlet busiestFlight=flights.max{$0.booked<$1.booked}\nprint(\"=========== AIRLINE RESERVATION SYSTEM ===========\")\nprint(\"Flights:\",flights.count)\nprint(\"Passengers:\",passengers.count)\nprint(\"Bookings:\",bookings.count)\nprint(\"Total Seats:\",totalSeats)\nprint(\"Booked Seats:\",bookedSeats)\nprint(\"Available Seats:\",availableSeats)\nprint(\"Checked In:\",checkedPassengers.count)\nprint(\"Confirmed Bookings:\",confirmedBookings.count)\nprint(\"Revenue:\",totalRevenue)\nif let flight=busiestFlight{print(\"Highest Occupancy:\",flight.id,flight.booked)}\nprint(\"===== FLIGHT SCHEDULE =====\")\nflights.forEach{print($0.id,$0.from,\"->\",$0.to,$0.status,$0.price)}\nprint(\"===== PASSENGERS =====\")\npassengers.forEach{print($0.id,$0.name,$0.flight,$0.seat,$0.checkedIn)}\nprint(\"===== BOOKINGS =====\")\nbookings.forEach{print($0.id,$0.passenger,$0.flight,$0.payment,$0.method,$0.confirmed)}\nlet terminals=[\"T1\":\"Domestic\",\"T2\":\"International\",\"T3\":\"VIP\",\"Cargo\":\"Open\",\"Security\":\"Active\",\"Immigration\":\"Ready\",\"Baggage\":\"Running\"]\nprint(\"===== TERMINALS =====\")\nterminals.forEach{print($0.key,$0.value)}\nlet services=[\"Online Check-In\",\"Seat Upgrade\",\"Meal Booking\",\"Live Tracking\",\"Priority Boarding\",\"Lounge Access\",\"Travel Insurance\",\"Flight Alerts\",\"Airport Taxi\",\"Customer Support\"]\nprint(\"===== SERVICES =====\")\nservices.forEach{print($0)}\nlet system=[\"Server\":\"Online\",\"Radar\":\"Connected\",\"Weather\":\"Clear\",\"Runway\":\"Available\",\"Fuel\":\"Normal\",\"Security\":\"Enabled\",\"Backup\":\"Completed\",\"Database\":\"Healthy\",\"Version\":\"10.5.2\"]\nprint(\"===== CONTROL PANEL =====\")\nsystem.forEach{print($0.key,$0.value)}\nprint(\"Airline Reservation System Ready\")`  }
