      { name: "Rust Project 2", code:`#[derive(Debug,Clone)]\nstruct Product{ id:i32, name:String, price:i32, stock:i32 }\n#[derive(Debug,Clone)]\nstruct Customer{ id:i32, name:String, orders:i32, spent:i32 }\n#[derive(Debug,Clone)]\nstruct Order{ id:i32, product:String, qty:i32, total:i32 }\nfn main(){\nlet products=vec![\nProduct{id:1,name:\"Laptop\".to_string(),price:70000,stock:12},\nProduct{id:2,name:\"Mouse\".to_string(),price:1500,stock:50},\nProduct{id:3,name:\"Keyboard\".to_string(),price:3000,stock:40}\n];\nlet customers=vec![\nCustomer{id:1,name:\"Aman\".to_string(),orders:12,spent:185000},\nCustomer{id:2,name:\"Neha\".to_string(),orders:9,spent:98000},\nCustomer{id:3,name:\"Ravi\".to_string(),orders:5,spent:35400}\n];\nlet orders=vec![\nOrder{id:101,product:\"Laptop\".to_string(),qty:1,total:70000},\nOrder{id:102,product:\"Mouse\".to_string(),qty:2,total:3000},\nOrder{id:103,product:\"Keyboard\".to_string(),qty:1,total:3000}\n];\nlet stock:i32=products.iter().map(|p|p.stock).sum();\nlet revenue:i32=orders.iter().map(|o|o.total).sum();\nlet top=customers.iter().max_by_key(|c|c.orders);\nprintln!(\"STORE SYSTEM\");\nprintln!(\"PRODUCTS:{} STOCK:{}\",products.len(),stock);\nprintln!(\"CUSTOMERS:{} TOP:{:?}\",customers.len(),top);\nprintln!(\"REVENUE:{}\",revenue);\n}\n` },
      { name: "Rust Project 3", code:`#[derive(Debug,Clone)]\nstruct Product{ id:i32,name:String,price:i32,stock:i32 }\n#[derive(Debug,Clone)]\nstruct User{ id:i32,name:String,email:String }\n#[derive(Debug,Clone)]\nstruct Order{ id:i32,user:i32,product:i32,qty:i32,total:i32 }\nfn main(){\nlet mut products=vec![];\nlet mut users=vec![];\nlet mut orders=vec![];\nfn add_p(v:&mut Vec<Product>,n:&str,p:i32,s:i32){v.push(Product{id:v.len() as i32+1,name:n.to_string(),price:p,stock:s});}\nfn add_u(v:&mut Vec<User>,n:&str,e:&str){v.push(User{id:v.len() as i32+1,name:n.to_string(),email:e.to_string()});}\nfn order(u:&mut Vec<User>,p:&mut Vec<Product>,o:&mut Vec<Order>,uid:i32,pid:i32,q:i32){let pr=p.iter_mut().find(|x|x.id==pid);if let Some(x)=pr{if x.stock<q{return;}let total=x.price*q;x.stock-=q;o.push(Order{id:o.len() as i32+1,user:uid,product:pid,qty:q,total});}}\nadd_p(&mut products,\"Laptop\",70000,10);\nadd_p(&mut products,\"Mouse\",1500,50);\nadd_u(&mut users,\"Aman\",\"a@mail.com\");\norder(&mut users,&mut products,&mut orders,1,1,1);\nprintln!(\"{} {} {}\",users.len(),products.len(),orders.len());\n}\n`  },
      { name: "Rust Project 4", code:`#[derive(Debug,Clone)]\nstruct Product{ id:i32,name:String,price:i32,stock:i32 }\n#[derive(Debug,Clone)]\nstruct User{ id:i32,name:String,email:String,active:bool }\n#[derive(Debug,Clone)]\nstruct Order{ id:i32,user:i32,product:i32,qty:i32,total:i32 }\nfn main(){\nlet mut products=vec![];\nlet mut users=vec![];\nlet mut orders=vec![];\nfn add_p(v:&mut Vec<Product>,n:&str,p:i32,s:i32){v.push(Product{id:v.len() as i32+1,name:n.to_string(),price:p,stock:s});}\nfn add_u(v:&mut Vec<User>,n:&str,e:&str,a:bool){v.push(User{id:v.len() as i32+1,name:n.to_string(),email:e.to_string(),active:a});}\nfn order(u:&mut Vec<User>,p:&mut Vec<Product>,o:&mut Vec<Order>,uid:i32,pid:i32,q:i32){if let Some(x)=p.iter_mut().find(|x|x.id==pid){if x.stock<q{return;}let total=x.price*q;x.stock-=q;o.push(Order{id:o.len() as i32+1,user:uid,product:pid,qty:q,total});}}\nadd_p(&mut products,\"Laptop\",70000,10);\nadd_p(&mut products,\"Mouse\",1500,50);\nadd_p(&mut products,\"Keyboard\",3000,30);\nadd_u(&mut users,\"Aman\",\"a@mail.com\",true);\nadd_u(&mut users,\"Neha\",\"n@mail.com\",true);\nadd_u(&mut users,\"Ravi\",\"r@mail.com\",false);\norder(&mut users,&mut products,&mut orders,1,1,1);\norder(&mut users,&mut products,&mut orders,2,2,2);\nprintln!(\"Products:{} Users:{} Orders:{}\",products.len(),users.len(),orders.len());\n}\n` },
      { name: "Rust Project 5", code:`#[derive(Debug,Clone)]\nstruct User{ id:i32, name:String, email:String, city:String }\n#[derive(Debug,Clone)]\nstruct Product{ id:i32, name:String, price:i32 }\n#[derive(Debug,Clone)]\nstruct Order{ id:i32, user:String, product:String, qty:i32, total:i32 }\nfn main(){\nlet mut users:Vec<User>=vec![];\nlet mut products:Vec<Product>=vec![];\nlet mut orders:Vec<Order>=vec![];\nfn add_user(users:&mut Vec<User>,name:&str,email:&str,city:&str){users.push(User{id:users.len() as i32+1,name:name.to_string(),email:email.to_string(),city:city.to_string()});}\nfn add_product(products:&mut Vec<Product>,name:&str,price:i32){products.push(Product{id:products.len() as i32+1,name:name.to_string(),price});}\nfn place_order(users:&Vec<User>,products:&mut Vec<Product>,orders:&mut Vec<Order>,user:&str,product:&str,qty:i32){\nif users.iter().find(|u|u.name==user).is_none(){println!(\"User not found\");return;}\nif let Some(p)=products.iter_mut().find(|p|p.name==product){let total=p.price*qty;orders.push(Order{id:orders.len() as i32+1,user:user.to_string(),product:product.to_string(),qty,total});println!(\"Order Placed {}\",total);}else{println!(\"Product not found\");}\n}\nadd_user(&mut users,\"Aman\",\"a@mail.com\",\"Pune\");\nadd_user(&mut users,\"Neha\",\"n@mail.com\",\"Mumbai\");\nadd_product(&mut products,\"Laptop\",70000);\nadd_product(&mut products,\"Mouse\",1500);\nplace_order(&users,&mut products,&mut orders,\"Aman\",\"Laptop\",1);\nprintln!(\"{:?}\",users);\nprintln!(\"{:?}\",products);\nprintln!(\"{:?}\",orders);\n}\n` },
      { name: "Rust Project 6", code:`use std::collections::HashMap;\n#[derive(Debug)]\nstruct Product{id:u32,name:String,category:String,price:u32,stock:u32,sold:u32,available:bool}\n#[derive(Debug)]\nstruct Customer{id:u32,name:String,orders:u32,spent:u32,premium:bool}\n#[derive(Debug)]\nstruct Order{id:u32,customer:String,product:String,qty:u32,total:u32,status:String}\nfn main(){\nlet products=vec![\nProduct{id:101,name:String::from("Laptop"),category:String::from("Electronics"),price:72000,stock:28,sold:164,available:true},\nProduct{id:102,name:String::from("Keyboard"),category:String::from("Accessories"),price:3500,stock:75,sold:312,available:true},\nProduct{id:103,name:String::from("Mouse"),category:String::from("Accessories"),price:1800,stock:120,sold:486,available:true},\nProduct{id:104,name:String::from("Monitor"),category:String::from("Electronics"),price:18500,stock:36,sold:152,available:true},\nProduct{id:105,name:String::from("Headphones"),category:String::from("Audio"),price:6200,stock:54,sold:241,available:true},\nProduct{id:106,name:String::from("SSD"),category:String::from("Storage"),price:7900,stock:43,sold:196,available:true}\n];\nlet customers=vec![\nCustomer{id:1,name:String::from("Aman"),orders:15,spent:128000,premium:true},\nCustomer{id:2,name:String::from("Neha"),orders:11,spent:96000,premium:true},\nCustomer{id:3,name:String::from("Ravi"),orders:6,spent:25400,premium:false},\nCustomer{id:4,name:String::from("Priya"),orders:18,spent:175000,premium:true},\nCustomer{id:5,name:String::from("Arjun"),orders:9,spent:48300,premium:false}\n];\nlet orders=vec![\nOrder{id:1001,customer:String::from("Aman"),product:String::from("Laptop"),qty:1,total:72000,status:String::from("Delivered")},\nOrder{id:1002,customer:String::from("Neha"),product:String::from("Monitor"),qty:1,total:18500,status:String::from("Delivered")},\nOrder{id:1003,customer:String::from("Priya"),product:String::from("SSD"),qty:2,total:15800,status:String::from("Processing")},\nOrder{id:1004,customer:String::from("Arjun"),product:String::from("Mouse"),qty:3,total:5400,status:String::from("Delivered")},\nOrder{id:1005,customer:String::from("Ravi"),product:String::from("Keyboard"),qty:1,total:3500,status:String::from("Packed")}\n];\nlet total_stock:u32=products.iter().map(|p|p.stock).sum();\nlet total_sold:u32=products.iter().map(|p|p.sold).sum();\nlet inventory_value:u32=products.iter().map(|p|p.price*p.stock).sum();\nlet revenue:u32=orders.iter().map(|o|o.total).sum();\nlet premium_count=customers.iter().filter(|c|c.premium).count();\nlet available_count=products.iter().filter(|p|p.available).count();\nlet best=products.iter().max_by_key(|p|p.sold).unwrap();\nlet mut dashboard=HashMap::new();\ndashboard.insert("Server","Online");\ndashboard.insert("Database","Connected");\ndashboard.insert("Cache","Running");\ndashboard.insert("Security","Enabled");\ndashboard.insert("Payments","Active");\ndashboard.insert("Backup","Completed");\ndashboard.insert("Version","2.5.1");\nprintln!("=========== RUST STORE MANAGEMENT ===========");\nprintln!("Products:{}",products.len());\nprintln!("Customers:{}",customers.len());\nprintln!("Orders:{}",orders.len());\nprintln!("Available Products:{}",available_count);\nprintln!("Premium Customers:{}",premium_count);\nprintln!("Stock:{}",total_stock);\nprintln!("Sold:{}",total_sold);\nprintln!("Inventory Value:{}",inventory_value);\nprintln!("Revenue:{}",revenue);\nprintln!("Best Seller:{} {}",best.name,best.sold);\nprintln!("=====PRODUCTS=====");\nfor p in &products{println!("{} {} {} {} {} {}",p.id,p.name,p.category,p.price,p.stock,p.sold);}\nprintln!("=====CUSTOMERS=====");\nfor c in &customers{println!("{} {} {} {} {}",c.id,c.name,c.orders,c.spent,c.premium);}\nprintln!("=====ORDERS=====");\nfor o in &orders{println!("{} {} {} {} {} {}",o.id,o.customer,o.product,o.qty,o.total,o.status);}\nprintln!("=====SYSTEM=====");\nfor(k,v)in &dashboard{println!("{} {}",k,v);}\nlet modules=vec!["Dashboard","Inventory","Orders","Customers","Payments","Reports","Analytics","Support","Settings"];\nprintln!("=====MODULES=====");\nfor m in modules{println!("{}",m);}\nprintln!("Rust E-Commerce Backend Started Successfully");\n}`  },
      { name: "Rust Project 7", code:`use std::collections::HashMap;\n#[derive(Debug)]\nstruct Student{roll:u32,name:String,course:String,marks:Vec<u32>,attendance:u32}\nfn average(v:&Vec<u32>)->u32{v.iter().sum::<u32>()/v.len() as u32}\nfn grade(m:u32)->String{if m>=90{String::from("A+")}else if m>=75{String::from("A")}else if m>=60{String::from("B")}else{String::from("C")}}\nfn main(){\nlet students=vec![\nStudent{roll:1,name:String::from("Aman"),course:String::from("Rust"),marks:vec![88,91,94,90],attendance:96},\nStudent{roll:2,name:String::from("Neha"),course:String::from("AI"),marks:vec![79,82,77,85],attendance:93},\nStudent{roll:3,name:String::from("Ravi"),course:String::from("Cloud"),marks:vec![68,71,74,70],attendance:89},\nStudent{roll:4,name:String::from("Priya"),course:String::from("Cyber"),marks:vec![96,94,98,99],attendance:99},\nStudent{roll:5,name:String::from("Arjun"),course:String::from("Web"),marks:vec![84,80,87,86],attendance:91}\n];\nlet mut report=HashMap::new();\nreport.insert("Semester","Final");\nreport.insert("Result","Published");\nreport.insert("Server","Online");\nreport.insert("Database","Connected");\nlet mut total_avg=0;\nlet mut topper=String::new();\nlet mut top_marks=0;\nprintln!("==========RUST STUDENT PORTAL==========");\nfor s in &students{\nlet avg=average(&s.marks);\ntotal_avg+=avg;\nif avg>top_marks{top_marks=avg;topper=s.name.clone();}\nprintln!(\"{} {} {} Avg:{} Grade:{} Attendance:{}%\",s.roll,s.name,s.course,avg,grade(avg),s.attendance);\n}\nprintln!(\"Students:{}\",students.len());\nprintln!(\"Class Average:{}\",total_avg/students.len() as u32);\nprintln!(\"Topper:{} {}\",topper,top_marks);\nprintln!(\"=====SYSTEM STATUS=====\");\nfor(k,v)in &report{println!(\"{}:{}\",k,v);}\nlet notices=vec![\"Exam Completed\",\"Certificates Ready\",\"Placement Drive\",\"Holiday Notice\",\"Project Submission\"];\nprintln!(\"=====NOTICES=====\");\nfor n in notices{println!(\"{}\",n);}\nprintln!(\"Student Portal Closed Successfully\");}` },
      { name: "Rust Project 8", code:`use std::collections::HashMap;\n#[derive(Debug)]\nstruct Flight{id:u32,code:String,from:String,to:String,seats:u32,booked:u32,price:u32,status:String}\n#[derive(Debug)]\nstruct Passenger{id:u32,name:String,flight:String,seat:String,paid:bool}\nfn main(){\nlet flights=vec![\nFlight{id:1,code:String::from("AI101"),from:String::from("Delhi"),to:String::from("Mumbai"),seats:180,booked:154,price:6200,status:String::from("OnTime")},\nFlight{id:2,code:String::from("AI205"),from:String::from("Pune"),to:String::from("Bengaluru"),seats:160,booked:149,price:5400,status:String::from("Boarding")},\nFlight{id:3,code:String::from("AI309"),from:String::from("Hyderabad"),to:String::from("Chennai"),seats:150,booked:112,price:4100,status:String::from("Delayed")},\nFlight{id:4,code:String::from("AI410"),from:String::from("Jaipur"),to:String::from("Goa"),seats:170,booked:165,price:7800,status:String::from("OnTime")},\nFlight{id:5,code:String::from("AI555"),from:String::from("Kolkata"),to:String::from("Delhi"),seats:190,booked:175,price:6900,status:String::from("Scheduled")}\n];\nlet passengers=vec![\nPassenger{id:1,name:String::from("Aman"),flight:String::from("AI101"),seat:String::from("12A"),paid:true},\nPassenger{id:2,name:String::from("Neha"),flight:String::from("AI205"),seat:String::from("08C"),paid:true},\nPassenger{id:3,name:String::from("Ravi"),flight:String::from("AI309"),seat:String::from("15D"),paid:false},\nPassenger{id:4,name:String::from("Priya"),flight:String::from("AI410"),seat:String::from("02F"),paid:true},\nPassenger{id:5,name:String::from("Arjun"),flight:String::from("AI555"),seat:String::from("21B"),paid:true},\nPassenger{id:6,name:String::from("Karan"),flight:String::from("AI101"),seat:String::from("16A"),paid:true},\nPassenger{id:7,name:String::from("Pooja"),flight:String::from("AI205"),seat:String::from("10E"),paid:false}\n];\nlet total_seats:u32=flights.iter().map(|f|f.seats).sum();\nlet booked:u32=flights.iter().map(|f|f.booked).sum();\nlet revenue:u32=flights.iter().map(|f|f.booked*f.price).sum();\nlet available=total_seats-booked;\nlet busiest=flights.iter().max_by_key(|f|f.booked).unwrap();\nlet paid_count=passengers.iter().filter(|p|p.paid).count();\nlet pending_count=passengers.len()-paid_count;\nlet mut system=HashMap::new();\nsystem.insert("Server","Online");\nsystem.insert("Radar","Connected");\nsystem.insert("Weather","Clear");\nsystem.insert("Security","Active");\nsystem.insert("CheckIn","Running");\nsystem.insert("Boarding","Enabled");\nsystem.insert("Database","Connected");\nsystem.insert("Version","5.4.2");\nprintln!("===========RUST AIRPORT MANAGEMENT===========");\nprintln!("Flights:{}",flights.len());\nprintln!("Passengers:{}",passengers.len());\nprintln!("Seats:{}",total_seats);\nprintln!("Booked:{}",booked);\nprintln!("Available:{}",available);\nprintln!("Revenue:{}",revenue);\nprintln!("Paid Tickets:{}",paid_count);\nprintln!("Pending Payments:{}",pending_count);\nprintln!("Busiest Flight:{} {}",busiest.code,busiest.booked);\nprintln!("=====FLIGHTS=====");\nfor f in &flights{println!(\"{} {} {} {} {} {} {} {}\",f.id,f.code,f.from,f.to,f.seats,f.booked,f.price,f.status);}\nprintln!(\"=====PASSENGERS=====\");\nfor p in &passengers{println!(\"{} {} {} {} {}\",p.id,p.name,p.flight,p.seat,p.paid);}\nprintln!(\"=====SYSTEM=====\");\nfor(k,v)in &system{println!(\"{} {}\",k,v);}\nlet services=vec![\"Online Booking\",\"Live Tracking\",\"Baggage\",\"Food Service\",\"VIP Lounge\",\"Mobile CheckIn\",\"Refund\",\"Customer Support\",\"Emergency Desk\",\"Flight Analytics\",\"Security Monitor\",\"Schedule Manager\"];\nprintln!(\"=====SERVICES=====\");\nfor s in services{println!(\"{}\",s);}\nprintln!(\"Airport Control System Running Successfully\");}` },
      { name: "Rust Project 9", code:`use std::collections::HashMap;\n#[derive(Debug)]\nstruct User{id:u32,name:String,email:String,role:String,active:bool,login:u32}\n#[derive(Debug)]\nstruct Project{id:u32,title:String,owner:String,progress:u32,tasks:u32,completed:u32}\n#[derive(Debug)]\nstruct Server{name:String,cpu:u32,memory:u32,storage:u32,status:String}\nfn main(){\nlet users=vec![\nUser{id:1,name:String::from("Aman"),email:String::from("aman@mail.com"),role:String::from("Admin"),active:true,login:148},\nUser{id:2,name:String::from("Neha"),email:String::from("neha@mail.com"),role:String::from("Designer"),active:true,login:121},\nUser{id:3,name:String::from("Ravi"),email:String::from("ravi@mail.com"),role:String::from("Developer"),active:true,login:165},\nUser{id:4,name:String::from("Priya"),email:String::from("priya@mail.com"),role:String::from("Tester"),active:false,login:89},\nUser{id:5,name:String::from("Arjun"),email:String::from("arjun@mail.com"),role:String::from("Manager"),active:true,login:204},\nUser{id:6,name:String::from("Karan"),email:String::from("karan@mail.com"),role:String::from("Support"),active:true,login:97}\n];\nlet projects=vec![\nProject{id:101,title:String::from("Client Portal"),owner:String::from("Aman"),progress:82,tasks:120,completed:98},\nProject{id:102,title:String::from("Admin Dashboard"),owner:String::from("Neha"),progress:71,tasks:96,completed:68},\nProject{id:103,title:String::from("Cloud API"),owner:String::from("Ravi"),progress:91,tasks:144,completed:132},\nProject{id:104,title:String::from("Analytics"),owner:String::from("Arjun"),progress:64,tasks:110,completed:70},\nProject{id:105,title:String::from("Security Panel"),owner:String::from("Karan"),progress:55,tasks:88,completed:49}\n];\nlet servers=vec![\nServer{name:String::from("Auth"),cpu:42,memory:61,storage:55,status:String::from("Online")},\nServer{name:String::from("API"),cpu:68,memory:72,storage:63,status:String::from("Online")},\nServer{name:String::from("Database"),cpu:74,memory:81,storage:79,status:String::from("Online")},\nServer{name:String::from("Backup"),cpu:31,memory:45,storage:90,status:String::from("Running")},\nServer{name:String::from("Analytics"),cpu:59,memory:66,storage:71,status:String::from("Online")}\n];\nlet total_logins:u32=users.iter().map(|u|u.login).sum();\nlet active_users=users.iter().filter(|u|u.active).count();\nlet total_tasks:u32=projects.iter().map(|p|p.tasks).sum();\nlet completed_tasks:u32=projects.iter().map(|p|p.completed).sum();\nlet avg_progress:u32=projects.iter().map(|p|p.progress).sum::<u32>()/projects.len() as u32;\nlet busiest=projects.iter().max_by_key(|p|p.completed).unwrap();\nlet mut config=HashMap::new();\nconfig.insert("Environment","Production");\nconfig.insert("Version","8.4.1");\nconfig.insert("Database","Connected");\nconfig.insert("Cache","Enabled");\nconfig.insert("Firewall","Active");\nconfig.insert("Backup","Completed");\nconfig.insert("Monitoring","Running");\nconfig.insert("API","Healthy");\nconfig.insert("Scheduler","Online");\nprintln!("=============RUST WEB PLATFORM=============");\nprintln!("Users:{}",users.len());\nprintln!("Active Users:{}",active_users);\nprintln!("Projects:{}",projects.len());\nprintln!("Servers:{}",servers.len());\nprintln!("Logins:{}",total_logins);\nprintln!("Tasks:{}/{}",completed_tasks,total_tasks);\nprintln!("Average Progress:{}%",avg_progress);\nprintln!("Top Project:{} {}%",busiest.title,busiest.progress);\nprintln!("=====USERS=====");\nfor u in &users{println!(\"{} {} {} {} {} {}\",u.id,u.name,u.email,u.role,u.active,u.login);}\nprintln!(\"=====PROJECTS=====\");\nfor p in &projects{println!(\"{} {} {} {} {} {}\",p.id,p.title,p.owner,p.progress,p.tasks,p.completed);}\nprintln!(\"=====SERVERS=====\");\nfor s in &servers{println!(\"{} CPU:{} MEM:{} DISK:{} {}\",s.name,s.cpu,s.memory,s.storage,s.status);}\nprintln!(\"=====CONFIG=====\");\nfor(k,v)in &config{println!(\"{} {}\",k,v);}\nlet modules=vec![\"Dashboard\",\"Authentication\",\"Users\",\"Projects\",\"Tasks\",\"Analytics\",\"Notifications\",\"Reports\",\"Cloud Sync\",\"Billing\",\"Security\",\"Support\",\"Settings\",\"Logs\",\"Monitoring\"];\nprintln!(\"=====MODULES=====\");\nfor m in modules{println!(\"{}\",m);}\nprintln!(\"Rust Enterprise Platform Started Successfully\");}`  },
      { name: "Rust Project 10", code:`use std::collections::HashMap;\n#[derive(Debug)]\nstruct Device{id:u32,name:String,ip:String,cpu:u32,ram:u32,disk:u32,online:bool}\n#[derive(Debug)]\nstruct Alert{id:u32,level:String,message:String,resolved:bool}\n#[derive(Debug)]\nstruct Service{name:String,requests:u32,errors:u32,uptime:f32}\nfn main(){\nlet devices=vec![\nDevice{id:1,name:String::from("Gateway"),ip:String::from("10.0.0.1"),cpu:34,ram:42,disk:61,online:true},\nDevice{id:2,name:String::from("WebServer"),ip:String::from("10.0.0.2"),cpu:67,ram:74,disk:58,online:true},\nDevice{id:3,name:String::from("Database"),ip:String::from("10.0.0.3"),cpu:81,ram:79,disk:83,online:true},\nDevice{id:4,name:String::from("Cache"),ip:String::from("10.0.0.4"),cpu:29,ram:38,disk:41,online:true},\nDevice{id:5,name:String::from("Storage"),ip:String::from("10.0.0.5"),cpu:58,ram:66,disk:92,online:true},\nDevice{id:6,name:String::from("Backup"),ip:String::from("10.0.0.6"),cpu:21,ram:34,disk:95,online:true},\nDevice{id:7,name:String::from("Analytics"),ip:String::from("10.0.0.7"),cpu:73,ram:69,disk:64,online:false}\n];\nlet alerts=vec![\nAlert{id:101,level:String::from("High"),message:String::from("CPU Usage"),resolved:false},\nAlert{id:102,level:String::from("Medium"),message:String::from("Memory Warning"),resolved:true},\nAlert{id:103,level:String::from("Low"),message:String::from("Disk Cleanup"),resolved:true},\nAlert{id:104,level:String::from("Critical"),message:String::from("Network Timeout"),resolved:false},\nAlert{id:105,level:String::from("Medium"),message:String::from("Backup Delay"),resolved:true}\n];\nlet services=vec![\nService{name:String::from("Login"),requests:14230,errors:11,uptime:99.98},\nService{name:String::from("Payment"),requests:9542,errors:6,uptime:99.95},\nService{name:String::from("API"),requests:28341,errors:21,uptime:99.91},\nService{name:String::from("Storage"),requests:12560,errors:4,uptime:99.99},\nService{name:String::from("Notification"),requests:18452,errors:9,uptime:99.93}\n];\nlet online=devices.iter().filter(|d|d.online).count();\nlet offline=devices.len()-online;\nlet cpu_avg=devices.iter().map(|d|d.cpu).sum::<u32>()/devices.len() as u32;\nlet ram_avg=devices.iter().map(|d|d.ram).sum::<u32>()/devices.len() as u32;\nlet disk_avg=devices.iter().map(|d|d.disk).sum::<u32>()/devices.len() as u32;\nlet total_requests:u32=services.iter().map(|s|s.requests).sum();\nlet total_errors:u32=services.iter().map(|s|s.errors).sum();\nlet unresolved=alerts.iter().filter(|a|!a.resolved).count();\nlet mut status=HashMap::new();\nstatus.insert("Cluster","Healthy");\nstatus.insert("Database","Connected");\nstatus.insert("Firewall","Enabled");\nstatus.insert("SSL","Active");\nstatus.insert("Scheduler","Running");\nstatus.insert("Backup","Completed");\nstatus.insert("Monitoring","Enabled");\nstatus.insert("Version","10.2.0");\nprintln!("===========RUST NETWORK OPERATIONS CENTER===========");\nprintln!("Devices:{} Online:{} Offline:{}",devices.len(),online,offline);\nprintln!("CPU Avg:{} RAM Avg:{} Disk Avg:{}",cpu_avg,ram_avg,disk_avg);\nprintln!("Requests:{} Errors:{}",total_requests,total_errors);\nprintln!("Alerts:{} Unresolved:{}",alerts.len(),unresolved);\nprintln!("=====DEVICES=====");\nfor d in &devices{println!(\"{} {} {} CPU:{} RAM:{} DISK:{} {}\",d.id,d.name,d.ip,d.cpu,d.ram,d.disk,d.online);}\nprintln!(\"=====SERVICES=====\");\nfor s in &services{println!(\"{} Req:{} Err:{} Up:{}%\",s.name,s.requests,s.errors,s.uptime);}\nprintln!(\"=====ALERTS=====\");\nfor a in &alerts{println!(\"{} {} {} {}\",a.id,a.level,a.message,a.resolved);}\nprintln!(\"=====SYSTEM STATUS=====\");\nfor(k,v)in &status{println!(\"{} {}\",k,v);}\nlet modules=vec![\"Dashboard\",\"Devices\",\"Servers\",\"Alerts\",\"Traffic\",\"Security\",\"Analytics\",\"Logs\",\"Users\",\"Reports\",\"Automation\",\"Scheduler\",\"Cloud Sync\",\"API Gateway\",\"Terminal\",\"Settings\",\"Audit\",\"Performance\"];\nprintln!(\"=====MODULES=====\");\nfor m in modules{println!(\"{}\",m);}\nprintln!(\"Rust Network Operations Center Running Successfully\");}` }
